const d=document.getElementById("themeToggle"),e=document.getElementById("themeSun"),t=document.getElementById("themeMoon");function n(){document.documentElement.classList.contains("dark")?(e.classList.remove("hidden"),t.classList.add("hidden")):(e.classList.add("hidden"),t.classList.remove("hidden"))}n();d.addEventListener("click",()=>{document.documentElement.classList.contains("dark")?(document.documentElement.classList.remove("dark"),localStorage.setItem("color-theme","light")):(document.documentElement.classList.add("dark"),localStorage.setItem("color-theme","dark")),n()});
